INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-f29af906-moex-00678', 'elementary-f29af906', 'elementary-f29af906-moex-111-01c5eaab', 'sub-elementary-f29af906-05', NULL, 'single_choice', '「百年前，祖輩渡海來臺。彼時地景枯黃無綠，他們不分冬夏，將幾千幾百斤的汗水灑進地裡，但 乾渴的砂土仍張著龜裂大口張狂索求。被日光曬得刺燙燙的砂地如一塊烙鐵，驅趕著踩踏其上的農 人。但有人始終不走，他們直立旱地等待。日日夜夜，季季年年，終於等到灣寶庄農地重劃，興圳 建渠。可惜砂地如漏，水還未浸透，即迅速流逝。幸賴神明指引，庄民徒手徒腳、齊心齊力，共同 鏟挖庄內的紅色黏土丘，將其厚鋪於砂壤，仔細翻攪，此後，再灑下的幾千幾百斤汗水，才開始值 得。一直以來，灣寶的農民習於不著鞋履走入田地。早期因為窮困，如今則因田壟有水。泥糊糊， 溫潤潤，一踏進，就像裹上一層新生的肌膚。農人的掌有老繭，腰背僵硬，往往帶病在身。但他們 仍堅持走進農田，將鋤頭一次一次地劈進地裡。」 依據上文，下列敘述正確的是：', '["早期灣寶的地質惡劣，不利耕作", "灣寶農民以前習慣不穿鞋是因為生活貧困", "因為居住條件不佳，灣寶早已人去樓空，成為廢墟", "灣寶農民劈進地裡的不只是鋤頭，還有一股有志竟成的精神 灣寶土地改良的方式是將砂土與黏土和在一起，如此可避免砂壤大量流失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00679', 'elementary-f29af906', 'elementary-f29af906-moex-111-01c5eaab', 'sub-elementary-f29af906-05', NULL, 'single_choice', '「面對電腦的運算能力每兩年就會倍增的飆速發展，我們的社會結構一直處於落後科技發展的狀 態，唯一的方法就是增加社會的適應力，也就是要使學習的效益達到最佳化，並將創新特質運用到 文化與社會結構上，破除因循僵化、講求靈活應變，以縮短從錯誤學習的時間。大學課程的推陳出 新也日益加快，有些課程甚至已標上時效。而隨著創新週期愈來愈短，學習適應的時間愈來愈少， 我們所面對的穩定狀態也有了變化，只有不穩定的固定狀態以及偶爾不穩定狀態的差異，新的穩定 狀態必定是動態穩定，就像騎腳踏車一樣，必須在雙腳不停地踩動下一直前進。」 根據上文，說明正確的選項是：', '["人類社會的結構總是無法跟上電腦運算能力的迅速發展", "提高學習效益可增加社會的整體適應力，維持靜態穩定", "行政機關以穩定為要，避免因創新融入而帶來擾動不安", "為了符應社會變動的需求，大學開設時效課程將成為一種趨勢 最佳適應力表現在失敗後能快速修正，並維持動態平衡的前進"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00680', 'elementary-f29af906', 'elementary-f29af906-moex-111-01c5eaab', 'sub-elementary-f29af906-05', NULL, 'single_choice', '下列選項，適合平行機關間使用的是：', '["「檢陳」、「附送」", "「希查照」、「附送」", "「請查照」、「附送」", "「請查照」、「希查照」 「請查照」、「敬表同意」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00681', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例等規定，於下列何種情形下，原土地所有權人得主張徵收失效？', '["因工程變更設計，原徵收之土地不在工程用地範圍內", "徵收計畫開始使用前，興辦事業計畫遭註銷，已無使用土地之必要", "需用土地人因作業錯誤，致原徵收之土地不在工程用地範圍內", "直轄市或縣（市）主管機關未於法定期限內轉交發給補償費完竣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00682', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，關於應辦理廢止徵收的情況與條件，下列敘述何者正確？', '["廢止徵收應一律由原土地所有權人向內政部請求之", "廢止徵收應由需用土地人與原所有權人共同向內政部提出之", "廢止徵收由需用土地人向內政部提出", "廢止徵收得由原土地所有權人向地方法院提出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00683', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '都市計畫中規定應辦理區段徵收地區，其細部計畫已發布實施者，應於區段徵收範圍勘定後多久內完成 都市計畫樁位測定？', '["六週", "兩個月", "一個月", "三個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00684', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市計畫法第27條之1之規定，土地權利關係人自行擬定或變更細部計畫時，主管機關得要求變更回 饋項目，下列何者屬之？', '["公共設施用地或代金", "公共設施用地、可建築用地、樓地板面積或代金", "公共設施用地、可建築用地", "公共設施用地、可建築用地或代金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00685', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '若設定不動產役權之需役地滅失時，於其供役不動產之不動產役權應辦理何種登記？', '["塗銷登記", "消滅登記", "預告登記", "囑託登記"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00686', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法第160條規定，關於啟動重新規定地價的時機點，下列何者正確？', '["地價申報滿六年", "地價申報一年屆滿而地價已較原標準地價有百分之五十以上之增減時", "地價申報滿兩年而地價已較原標準地價有百分之五十以上之增減時", "地價申報屆滿十年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00687', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '有關區段徵收抵價地之分配，依照區段徵收實施辦法規定，下列何者錯誤？', '["各直轄市或縣（市）主管機關應會商需用土地人訂定抵價地分配作業要點，並依要點執行", "抵價地分配應以公開抽籤方式進行", "若土地所有權人死亡，其繼承人或遺產清理人應先完成繼承登記後方得申請發給抵價地", "原土地所有權人得自行選擇抵價地之分配街廓"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
